import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response
import java.io.IOException

class HttpClient {

    private val client = OkHttpClient()

    fun getFromLocalDevice(ipAddress: String, endpoint: String): String? {
        val url = "http://$ipAddress/$endpoint"
        return executeRequest(url)
    }

    fun getFromCloudApi(endpoint: String): String? {
        val url = "https://api.example.com/$endpoint"
        return executeRequest(url)
    }

    private fun executeRequest(url: String): String? {
        val request = Request.Builder()
            .url(url)
            .build()

        return try {
            client.newCall(request).execute().use { response -> handleResponse(response) }
        } catch (e: IOException) {
            e.printStackTrace()
            null
        }
    }

    private fun handleResponse(response: Response): String? {
        return if (response.isSuccessful) {
            response.body?.string()
        } else {
            println("Request failed: ${response.code}")
            null
        }
    }
}